extension.valueString:
/*
@internal: JE containing Doses Administered to Patient that are in the Primary series
*/
define "JE Primary Series Doses Administered to Patient":
  "JE Doses Administered to Patient".seriesPrimary()

/*
@internal: Number of JE Primary Series doses
*/
define "Number of JE Primary Series Doses Administered":
  Count("JE Primary Series Doses Administered to Patient")

/*
@input: No JE primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "JE vaccines" and "Type of dose" = "Primary series") = 0
@code: No JE primary series doses were administered-111
@decision: IMMZ.D2.DT.JE.Inactivated Vero cell-derived vaccine: Inactivated Vero cell-derived vaccination schedule (2-dose scheme)
JE vaccination should be integrated into national immunization schedules in all areas where JE is recognized as a public health priority
@decision: IMMZ.D2.DT.JE.Live attenuated vaccine: Live attenuated vaccination schedule (1-dose scheme)
JE vaccination should be integrated into national immunization schedules in all areas where JE is recognized as a public health priority
@decision: IMMZ.D2.DT.JE.Live recombinant vaccine: Live recombinant vaccination schedule (1-dose scheme)
JE vaccination should be integrated into national immunization schedules in all areas where JE is recognized as a public health priority
*/
define "No JE primary series doses were administered":
  "Number of JE Primary Series Doses Administered" = 0

/*
@input: One JE primary series dose was administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "JE vaccines" and "Type of dose" = "Primary series") = 1
@code: One JE primary series dose was administered-111
@decision: IMMZ.D2.DT.JE.Inactivated Vero cell-derived vaccine: Inactivated Vero cell-derived vaccination schedule (2-dose scheme)
JE vaccination should be integrated into national immunization schedules in all areas where JE is recognized as a public health priority
@decision: IMMZ.D2.DT.JE.Live attenuated vaccine: Live attenuated vaccination schedule (1-dose scheme)
JE vaccination should be integrated into national immunization schedules in all areas where JE is recognized as a public health priority
*/
define "One JE primary series dose was administered":
  "Number of JE Primary Series Doses Administered" = 1

/*
@input: One JE primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "JE vaccines" and "Type of dose" = "Primary series") = 1
@code: One JE primary series doses were administered-111
@decision: IMMZ.D2.DT.JE.Live recombinant vaccine: Live recombinant vaccination schedule (1-dose scheme)
JE vaccination should be integrated into national immunization schedules in all areas where JE is recognized as a public health priority
*/
define "One JE primary series doses were administered":
  "One JE primary series dose was administered"

/*
@complete: One JE dose from primary series was administered. The primary series has been completed
@pseudocode: "Completed the primary vaccination series" = TRUE (where "Vaccine type" = "JE vaccines")
*/
define "One JE dose from primary series was administered. The primary series has been completed":
  Encounter."One JE primary series doses were administered"

/*
@output: Japanese encephalitis (JE) dose 1
@description: Provision of the JE dose 1
@trigger: Child's birth
@pseudo: 
@triggerDate: "Date of birth"
*/
define "Japanese encephalitis (JE) dose 1":
  Encounter."No JE primary series doses were administered"
  and not "One JE dose from primary series was administered. The primary series has been completed"

/*
@dynamicValue: Japanese encephalitis (JE) dose 1 Due Date
@pseudocode: "Date of birth" + 9 months
*/
define "Japanese encephalitis (JE) dose 1 Due Date":
  if "Japanese encephalitis (JE) dose 1" then Patient.birthDate + 9 months
  else null

/*
@output: Japanese encephalitis (JE) dose 1 Create
@create: Live recombinant vaccine: Single dose administered at ≥9 months of age
*/
define "Japanese encephalitis (JE) dose 1 Create":
  if "Japanese encephalitis (JE) dose 1"
  then 'Live recombinant vaccine: Single dose administered at ≥9 months of age' + '
Due Date: ' + ToString("Japanese encephalitis (JE) dose 1 Due Date")
  else ''
